#!/usr/bin/env node
'use strict';

/**
 * agent-files-state.cjs - Shared detection for missing root agent-instruction files.
 *
 * Two root files bootstrap a portable .claude install:
 *   - CLAUDE.md  — Claude Code root instructions. Generated by /claude-md-init
 *                  (reads docs/project-config.json + template). AI-runnable.
 *   - AGENTS.md  — Codex/cross-tool root instructions. Generated mirror of CLAUDE.md
 *                  produced by /sync-codex or its standalone node runner.
 *
 * This lib is the single source of truth for "is a root agent file missing and what
 * fixes it" — consumed by both the UserPromptSubmit router (init-prompt-gate.cjs) and
 * the PreToolUse Skill router (agent-files-skill-gate.cjs). Pure detection: no process.exit.
 *
 * Path resolution uses CLAUDE_PROJECT_DIR so a copied .claude bootstraps in any folder.
 *
 * @module agent-files-state
 */

const fs = require('fs');
const path = require('path');
const { AGENT_FILES_DISMISSED_PATH, ensureProjectTmpDir } = require('./ck-paths.cjs');
const { getConfiguredProjectConfigPath } = require('./project-config-loader.cjs');

const PROJECT_DIR = process.env.CLAUDE_PROJECT_DIR || process.cwd();
const DISMISS_TTL_MS = 24 * 60 * 60 * 1000; // 1 day — matches the other init gates

// ── Universal-guides content contract ──────────────────────────────────────
// An existing CLAUDE.md/AGENTS.md is "complete" only if it carries the portable
// framework guides (workflow ask-confirm gate, workflow step-advancement + parallel-
// phase barrier, task-planning, code hierarchy, evidence rules).
// CANONICAL contract: the generator (claude-md-init/scripts/generate-claude-md.cjs)
// stamps the sentinel below; bumping UNIVERSAL_GUIDES_VERSION re-offers an update on
// every previously-stamped file. The agent-files-gate.test.cjs sync test asserts the
// generator emits a marker matching this version — keep them in lockstep.
const UNIVERSAL_GUIDES_VERSION = 3;
const SENTINEL_RE = /<!--\s*CK:UNIVERSAL-GUIDES\s+v(\d+)\s*-->/i;
// Fallback for legacy/hand-written files with no sentinel: the static portable
// section headings the template always ships (see claude-md-template.md).
const REQUIRED_ANCHORS = [
    /first action decision/i, // the workflow ask-confirm gate
    /workflow step advancement/i, // model-driven advancement + parallel-phase barrier (hook-free, portable)
    /task planning rules/i,
    /code responsibility hierarchy/i,
    /evidence-based reasoning/i
];

/**
 * Canonical root agent files and the skill that (re)generates each.
 * `aiRunnable` distinguishes routes Claude can invoke itself (/claude-md-init) from
 * routes that may need a standalone script fallback.
 */
const AGENT_FILES = [
    {
        file: 'CLAUDE.md',
        route: '/claude-md-init',
        aiRunnable: true,
        why: 'Claude Code root instructions — generated from docs/project-config.json + template.'
    },
    {
        file: 'AGENTS.md',
        route: '/sync-codex',
        aiRunnable: false,
        fallbackCommand: 'node .claude/skills/sync-codex/scripts/run-codex-sync.mjs',
        why: 'Codex/cross-tool root instructions — generated mirror of CLAUDE.md.'
    }
];

/**
 * Does this content already carry the universal portable guides?
 * Hybrid: current-or-newer sentinel wins; otherwise fall back to requiring every
 * static anchor (covers legacy/hand-written-complete files with no sentinel).
 * @param {string} content
 * @returns {boolean}
 */
function hasUniversalGuides(content) {
    const text = content || '';
    const m = text.match(SENTINEL_RE);
    if (m) return Number(m[1]) >= UNIVERSAL_GUIDES_VERSION;
    return REQUIRED_ANCHORS.every(re => re.test(text));
}

/**
 * Is the universal-guides content check enabled for this project?
 * Opt-out: portability.requireUniversalGuides === false keeps a project-only file.
 * Defaults to true (and fail-open to true on any config read error).
 * @returns {boolean}
 */
function isUniversalGuidesRequired() {
    try {
        const configPath = getConfiguredProjectConfigPath();
        if (!fs.existsSync(configPath)) return true;
        const config = JSON.parse(fs.readFileSync(configPath, 'utf-8'));
        return config?.portability?.requireUniversalGuides !== false;
    } catch {
        return true; // fail-safe: default to requiring guides
    }
}

/**
 * Classify each root agent file: missing (route to init), incomplete (exists but
 * lacks the universal guides → route to update/smart-merge, preserving project
 * content), or ok (omitted). The incomplete check is skipped when the project has
 * opted out via portability.requireUniversalGuides.
 * @returns {Array<{file:string, route:string, aiRunnable:boolean, why:string, reason:'missing'|'incomplete', mode:'init'|'update'}>}
 */
function getAgentFileIssues() {
    const requireGuides = isUniversalGuidesRequired();
    const issues = [];
    for (const entry of AGENT_FILES) {
        const full = path.join(PROJECT_DIR, entry.file);
        let exists;
        try {
            exists = fs.existsSync(full);
        } catch {
            continue; // fail-open: unreadable → don't claim an issue
        }
        if (!exists) {
            issues.push({ ...entry, reason: 'missing', mode: 'init' });
            continue;
        }
        if (!requireGuides) continue; // existing file accepted as-is (opted out)
        let content;
        try {
            content = fs.readFileSync(full, 'utf-8');
        } catch {
            continue; // fail-open: unreadable → don't claim incomplete
        }
        if (!hasUniversalGuides(content)) {
            issues.push({ ...entry, reason: 'incomplete', mode: 'update' });
        }
    }
    return issues;
}

/**
 * Which root agent files are missing from the project root (existence only).
 * Retained for back-compat; new callers should prefer getAgentFileIssues().
 * @returns {Array<{file:string, route:string, aiRunnable:boolean, why:string}>}
 */
function getMissingAgentFiles() {
    return AGENT_FILES.filter(entry => {
        try {
            return !fs.existsSync(path.join(PROJECT_DIR, entry.file));
        } catch {
            return false; // fail-open: unreadable → don't claim missing
        }
    });
}

/**
 * True when at least one root agent file is missing or incomplete.
 * @returns {boolean}
 */
function hasMissingAgentFiles() {
    return getAgentFileIssues().length > 0;
}

/**
 * Dismiss flag valid (< TTL old)?
 * @returns {boolean}
 */
function isAgentFilesDismissed() {
    try {
        if (!fs.existsSync(AGENT_FILES_DISMISSED_PATH)) return false;
        const ageMs = Date.now() - fs.statSync(AGENT_FILES_DISMISSED_PATH).mtimeMs;
        return ageMs < DISMISS_TTL_MS;
    } catch {
        return false;
    }
}

/**
 * Write the dismiss flag with current timestamp.
 */
function writeAgentFilesDismissFlag() {
    try {
        ensureProjectTmpDir();
        fs.writeFileSync(AGENT_FILES_DISMISSED_PATH, new Date().toISOString() + '\n', 'utf-8');
    } catch {
        /* non-critical */
    }
}

/**
 * Is the prompt a dismiss request? Shares the "skip init" / "skip setup" phrase with
 * the project-config gate so one phrase silences the whole init nag for a day.
 * @param {string} prompt
 * @returns {boolean}
 */
function isAgentFilesDismissRequest(prompt) {
    return /skip\s*(init|setup)/i.test(prompt || '');
}

/**
 * Build the offer message instructing the AI to auto-route setup work.
 * Accepts getAgentFileIssues() output (entries carry reason/mode); also tolerates
 * legacy getMissingAgentFiles() output (no reason → treated as missing).
 * @param {Array} issues - output of getAgentFileIssues() (or getMissingAgentFiles())
 * @returns {string}
 */
function buildOfferMessage(issues) {
    const lines = issues.map(m => {
        const fallback = m.fallbackCommand ? ` or \`${m.fallbackCommand}\`` : '';
        const runner = m.aiRunnable ? `run ${m.route}${fallback}` : `ask the user to run ${m.route}${fallback}`;
        if (m.reason === 'incomplete') {
            return `  - ${m.file} present but missing the universal portable guides → ${runner} --mode update (smart-merge — preserves your project content)`;
        }
        return `  - ${m.file} missing → ${runner}`;
    });
    return [
        '',
        'Root agent-instruction file(s) need attention:',
        ...lines,
        '',
        'Preferred route:',
        '  /project-init        — initialize/re-evaluate config, docs, CLAUDE.md, AGENTS.md, and mirrors',
        '',
        'Targeted routes:',
        '  /claude-md-init       — generate or smart-merge CLAUDE.md from project-config + template',
        '  /sync-codex           — user-invoked only; generate AGENTS.md (Codex mirror of CLAUDE.md); use the node runner if the skill is unavailable',
        '  opt out permanently   — set portability.requireUniversalGuides=false in docs/project-config.json',
        '                          to keep a project-only file (disables the content check, not existence)',
        ''
    ].join('\n');
}

module.exports = {
    AGENT_FILES,
    DISMISS_TTL_MS,
    UNIVERSAL_GUIDES_VERSION,
    SENTINEL_RE,
    REQUIRED_ANCHORS,
    hasUniversalGuides,
    isUniversalGuidesRequired,
    getAgentFileIssues,
    getMissingAgentFiles,
    hasMissingAgentFiles,
    isAgentFilesDismissed,
    writeAgentFilesDismissFlag,
    isAgentFilesDismissRequest,
    buildOfferMessage
};
